#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        double expected = N;
        for (int i = 0; i < K; i++) {
            expected = (expected * (expected + 1)) / 2.0;
        }
        printf("%.6f\n", expected);
    }
    return 0;
}

