import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            double expected = N;
            for (int i = 0; i < K; i++) {
                expected = (expected * (expected + 1)) / 2.0;
            }
            System.out.printf("%.6f\n", expected);
        }
    }
}

